-- Уроки 9-16 курса промптинга
INSERT INTO t_p80207328_code_school_online.lessons
  (course_id, position, title, duration, intro, steps, software) VALUES

('ai-prompting', 9, 'Промпты для текстов и копирайтинга', '18:00',
'ИИ — мощный помощник в написании текстов: посты, письма, статьи, продающие описания. Но чтобы получить не «водянистый» текст, а рабочий, нужны специальные приёмы. Разберём промпты для разных типов контента и научимся задавать тон бренда.',
'[
  {"title": "Шаг 1. Продающий текст", "text": "Используй формулу: «Ты копирайтер. Напиши продающий текст для [товар]. Структура: боль клиента → решение → выгоды → призыв к действию. Тон уверенный, до 150 слов»."},
  {"title": "Шаг 2. Пост для соцсетей", "text": "«Напиши пост для Telegram-канала о [тема]. Зацепи первой строкой, дай пользу, закончи вопросом к аудитории. С эмодзи, до 500 знаков»."},
  {"title": "Шаг 3. Задай голос бренда", "text": "«Наш бренд говорит просто, с лёгким юмором, обращается на ты. Напиши в этом стиле анонс распродажи». ИИ подстроит тон."},
  {"title": "Шаг 4. Переработка текста", "text": "Вставь готовый текст и попроси: «Сделай этот текст живее и короче, убери канцелярит, сохрани смысл»."},
  {"title": "Шаг 5. Заголовки", "text": "«Придумай 10 вариантов заголовка для статьи о [тема]: 3 интригующих, 3 с цифрами, 4 с пользой». Выбирай лучший под задачу."}
]',
'[
  {"name": "ChatGPT", "desc": "Пишем тексты разных типов.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 10, 'Промпты для работы и учёбы', '16:00',
'ИИ экономит часы на рутине: резюме длинных текстов, подготовка к встречам, планы, конспекты, объяснение сложных тем. В этом уроке — набор рабочих промптов, которые пригодятся каждый день в офисе и на учёбе.',
'[
  {"title": "Шаг 1. Резюме длинного текста", "text": "Вставь большой текст и попроси: «Сделай краткое резюме в 5 пунктах, выдели главные мысли». Сэкономишь время на чтении."},
  {"title": "Шаг 2. Объяснение сложного", "text": "«Объясни, что такое инфляция, как для 10-летнего ребёнка, с примером из жизни». ИИ разложит любую тему просто."},
  {"title": "Шаг 3. Подготовка к встрече", "text": "«Я готовлюсь к переговорам с поставщиком о снижении цены. Составь список из 7 аргументов и возможных возражений»."},
  {"title": "Шаг 4. План и структура", "text": "«Составь план презентации на 10 слайдов о пользе спорта для сотрудников. Для каждого слайда — заголовок и 2 тезиса»."},
  {"title": "Шаг 5. Конспект и вопросы", "text": "«По этому тексту составь конспект и 5 вопросов для самопроверки». Отлично для подготовки к экзамену."}
]',
'[
  {"name": "ChatGPT", "desc": "Рабочие и учебные промпты.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 11, 'Генерация изображений: Midjourney и DALL-E', '20:00',
'Промпты нужны не только для текста — с их помощью создают картинки. Здесь свои правила: важны детали сцены, стиль, освещение, ракурс. Научимся описывать изображения так, чтобы нейросеть рисовала именно то, что ты представляешь.',
'[
  {"title": "Шаг 1. Выбери инструмент", "text": "Для картинок используй DALL-E (встроен в ChatGPT) или Midjourney. Начнём с DALL-E — просто попроси в чате: «Нарисуй...»."},
  {"title": "Шаг 2. Опиши объект и сцену", "text": "«Нарисуй уютную кофейню в дождливый вечер, тёплый свет из окон, люди за столиками». Чем детальнее сцена — тем лучше."},
  {"title": "Шаг 3. Добавь стиль", "text": "Укажи стиль: «в стиле акварели», «фотореализм», «3D-рендер», «минимализм». Например: «...в стиле акварельной иллюстрации»."},
  {"title": "Шаг 4. Управляй деталями", "text": "Добавь освещение, ракурс, цвета: «мягкое закатное освещение, вид сверху, тёплая палитра». Это как режиссура кадра."},
  {"title": "Шаг 5. Дорабатывай", "text": "Не понравилось — уточни: «Сделай светлее и добавь больше зелени». Генерируй варианты, пока не получишь нужный."}
]',
'[
  {"name": "ChatGPT (DALL-E)", "desc": "Генерация картинок прямо в чате.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN, открой chatgpt.com и попроси нарисовать изображение."},
  {"name": "Midjourney", "desc": "Профессиональная нейросеть для изображений (работает через Discord).", "url": "https://midjourney.com", "install": "⚠️ Потребуется VPN. Зарегистрируйся на midjourney.com, подключись через Discord."}
]'),

('ai-prompting', 12, 'Промпты для программирования', '18:00',
'ИИ отлично помогает с кодом даже новичкам: пишет функции, объясняет ошибки, комментирует чужой код. Даже если ты не программист — научишься просить ИИ решать технические задачи и понимать, что он выдал. Специальные приёмы для точного результата.',
'[
  {"title": "Шаг 1. Проси код с объяснением", "text": "«Напиши на Python функцию, которая считает сумму чисел в списке. Объясни каждую строку простыми словами»."},
  {"title": "Шаг 2. Разбор ошибки", "text": "Вставь ошибку из программы и попроси: «Объясни, что означает эта ошибка и как её исправить». ИИ переведёт с технического на человеческий."},
  {"title": "Шаг 3. Укажи уровень", "text": "«Я новичок, не знаю программирования. Объясни этот код так, будто мне 12 лет». ИИ упростит объяснение."},
  {"title": "Шаг 4. Проси готовое решение", "text": "«Мне нужна кнопка на сайте, которая при клике показывает сообщение. Дай готовый HTML и объясни, куда вставить»."},
  {"title": "Шаг 5. Улучшение кода", "text": "Вставь код и попроси: «Проверь на ошибки и предложи, как сделать лучше и понятнее»."}
]',
'[
  {"name": "ChatGPT", "desc": "Помощник по коду для любого уровня.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 13, 'Частые ошибки и как их избежать', '15:00',
'Даже опытные пользователи допускают ошибки в промптах, из-за которых ИИ отвечает не так. Разберём 7 главных ловушек: расплывчатость, перегруз, отсутствие контекста и другие. Зная их, ты сразу поднимешь качество своих запросов.',
'[
  {"title": "Ошибка 1. Слишком общий запрос", "text": "Плохо: «Помоги с бизнесом». Хорошо: «Дай 5 идей, как привлечь клиентов в барбершоп через Instagram». Всегда конкретизируй."},
  {"title": "Ошибка 2. Всё в одном промпте", "text": "Не проси сделать 10 разных вещей сразу — ИИ запутается. Разбивай сложную задачу на шаги в диалоге."},
  {"title": "Ошибка 3. Нет формата", "text": "Если не указать вид ответа, получишь сплошной текст. Всегда добавляй: список, таблица, столько-то пунктов."},
  {"title": "Ошибка 4. Не проверяешь факты", "text": "ИИ иногда выдумывает (это называют «галлюцинации»). Важные факты, цифры, цитаты всегда перепроверяй в источниках."},
  {"title": "Ошибка 5. Сдаёшься после первого ответа", "text": "Не нравится результат — не бросай, а уточняй и переделывай. Хороший ответ обычно рождается за 2-4 итерации."}
]',
'[
  {"name": "ChatGPT", "desc": "Отрабатываем избегание ошибок.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 14, 'Сравнение нейросетей: ChatGPT, Claude, Gemini', '16:00',
'ChatGPT — не единственный ИИ. У Claude, Gemini и других свои сильные стороны. В этом уроке разберём, чем они отличаются и какую нейросеть выбирать под конкретную задачу, чтобы получать лучший результат.',
'[
  {"title": "Шаг 1. ChatGPT", "text": "Универсал: тексты, код, картинки, диалог. Хорош почти для всего, большое сообщество. С него удобно начинать."},
  {"title": "Шаг 2. Claude", "text": "Силён в работе с длинными текстами и документами, аккуратен в рассуждениях, приятный «человечный» стиль. Хорош для анализа и больших текстов."},
  {"title": "Шаг 3. Gemini", "text": "Нейросеть от Google, хорошо интегрирована с поиском и сервисами Google, актуальная информация. Удобен, когда нужны свежие данные."},
  {"title": "Шаг 4. Проверь на своей задаче", "text": "Возьми один и тот же промпт и прогони его в разных нейросетях (там, где есть доступ). Сравни ответы — так поймёшь, что тебе ближе."},
  {"title": "Шаг 5. Вывод", "text": "Нет «лучшей» нейросети — есть подходящая под задачу. Промпты, которым ты научился, работают во всех: формула универсальна."}
]',
'[
  {"name": "ChatGPT", "desc": "Универсальная нейросеть.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."},
  {"name": "Claude", "desc": "Силён в длинных текстах и анализе.", "url": "https://claude.ai", "install": "⚠️ Потребуется VPN. Включи VPN и зарегистрируйся на claude.ai."},
  {"name": "Gemini", "desc": "Нейросеть Google с доступом к свежим данным.", "url": "https://gemini.google.com", "install": "⚠️ Потребуется VPN. Включи VPN и войди через Google-аккаунт на gemini.google.com."}
]'),

('ai-prompting', 15, 'Библиотека готовых промптов', '17:00',
'Соберём твою личную коллекцию проверенных промптов-шаблонов на каждый день. Их можно копировать, подставлять свои данные и использовать сразу. Также научимся сохранять и систематизировать удачные находки.',
'[
  {"title": "Шаг 1. Шаблон для текстов", "text": "Сохрани: «Ты копирайтер. Напиши [тип текста] о [тема] для [аудитория]. Тон [какой], формат [какой], объём [сколько]». Подставляй значения в скобках."},
  {"title": "Шаг 2. Шаблон для анализа", "text": "«Проанализируй [ситуация/текст]. Разбери пошагово: плюсы, минусы, риски, рекомендация». Универсален для любых решений."},
  {"title": "Шаг 3. Шаблон для обучения", "text": "«Объясни [тема] простыми словами с примером из жизни, затем задай мне 3 вопроса для проверки»."},
  {"title": "Шаг 4. Где хранить", "text": "Заведи заметку в телефоне или документ с лучшими промптами. Копируй удачные — со временем соберётся личная библиотека под твои задачи."},
  {"title": "Шаг 5. Практика", "text": "Составь 3 своих шаблона под задачи, которые встречаются чаще всего именно у тебя. Проверь их в ChatGPT и сохрани."}
]',
'[
  {"name": "ChatGPT", "desc": "Тестируем и собираем шаблоны.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 16, 'Финальный проект: реши реальную задачу', '25:00',
'Пора собрать все навыки вместе! Выбери реальную задачу из своей жизни или работы и реши её с помощью ИИ, применив всё изученное: роль, контекст, формат, примеры, итерации. Это твой выпускной проект курса.',
'[
  {"title": "Шаг 1. Выбери задачу", "text": "Возьми настоящую задачу: написать текст для сайта, спланировать мероприятие, составить резюме, придумать контент-план. Что-то полезное именно тебе."},
  {"title": "Шаг 2. Собери промпт по формуле", "text": "Примени всё: назначь ИИ роль эксперта, дай подробный контекст, укажи формат и ограничения. Не спеши — продумай запрос."},
  {"title": "Шаг 3. Используй примеры", "text": "Если нужен конкретный стиль — добавь 1-2 образца (техника few-shot из урока 5)."},
  {"title": "Шаг 4. Дорабатывай в диалоге", "text": "Получил черновик — критикуй и уточняй. Пройди 3-4 итерации, пока результат не станет по-настоящему хорошим."},
  {"title": "Шаг 5. Оцени результат", "text": "Сравни финальный результат с тем, что получилось бы от простого запроса «сделай мне...». Почувствуй разницу — теперь ты умеешь управлять ИИ. Поздравляю с окончанием курса! 🎉"}
]',
'[
  {"name": "ChatGPT", "desc": "Применяем все навыки в реальном проекте.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]');